use client";
import {
  DataTable,
  Button,
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
} from "@shery-ui/components";

import { ArrowUpDown, MoreHorizontal } from "lucide-react";
import { useMemo } from "react";

export default function DataTableDemo() {
  const data = useMemo(
    () => [
      {
        id: "pay_001",
        email: "olivia@example.com",
        status: "paid",
        amount: 250,
      },
      {
        id: "pay_002",
        email: "jack@example.com",
        status: "pending",
        amount: 150,
      },
      {
        id: "pay_003",
        email: "isabella@example.com",
        status: "failed",
        amount: 350,
      },
    ],
    []
  );

  const columns = useMemo(
    () => [
      {
        accessorKey: "email",
        header: ({ column }) => (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => column.toggleSorting()}
          >
            Email
            <ArrowUpDown className="ml-2 h-4 w-4" />
          </Button>
        ),
      },
      {
        accessorKey: "status",
        header: "Status",
      },
      {
        accessorKey: "amount",
        header: () => <div className="text-right">Amount</div>,
        cell: ({ row }) => {
          const amount = parseFloat(row.getValue("amount"));
          const formatted = new Intl.NumberFormat("en-US", {
            style: "currency",
            currency: "USD",
          }).format(amount);

          return (
            <div className="text-right font-medium">
              {formatted}
            </div>
          );
        },
      },
      {
        id: "actions",
        cell: () => (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="sm"
                className="h-8 w-8 p-0"
              >
                <MoreHorizontal className="h-4 w-4" />
              </Button>
            </DropdownMenuTrigger>

            <DropdownMenuContent align="end">
              <DropdownMenuLabel>
                Actions
              </DropdownMenuLabel>

              <DropdownMenuSeparator />

              <DropdownMenuItem>
                View details
              </DropdownMenuItem>

              <DropdownMenuItem>
                Copy ID
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        ),
      },
    ],
    []
  );

  return (
    <div className="w-full max-w-5xl">
      <DataTable
        columns={columns}
        data={data}
        filterColumn="email"
        filterPlaceholder="Filter emails..."
      />
    </div>
  );
}

"use client";
import {
  DataTable,
  Button,
} from "@shery-ui/components";

import { ArrowUpDown } from "lucide-react";
import { useMemo } from "react";

export default function DataTableSorting() {
  const data = useMemo(
    () => [
      {
        email: "olivia@example.com",
        status: "paid",
        amount: 250,
      },
      {
        email: "jack@example.com",
        status: "pending",
        amount: 150,
      },
      {
        email: "isabella@example.com",
        status: "failed",
        amount: 350,
      },
    ],
    []
  );

  const columns = useMemo(
    () => [
      {
        accessorKey: "email",
        header: ({ column }) => (
          <Button
            variant="ghost"
            size="sm"
            onClick={() =>
              column.toggleSorting(
                column.getIsSorted() === "asc"
              )
            }
          >
            Email
            <ArrowUpDown className="ml-2 h-4 w-4" />
          </Button>
        ),
      },
      {
        accessorKey: "status",
        header: "Status",
      },
      {
        accessorKey: "amount",
        header: "Amount",
      },
    ],
    []
  );

  return (
    <div className="w-full max-w-4xl">
      <DataTable
        columns={columns}
        data={data}
        showColumnVisibility={false}
      />
    </div>
  );
}

"use client";
import { DataTable } from "@shery-ui/components";
import { useMemo } from "react";

export default function DataTableSelection() {
  const data = useMemo(
    () => [
      {
        id: "usr_001",
        name: "Olivia Martin",
        role: "Frontend Developer",
        email: "olivia@example.com",
      },
      {
        id: "usr_002",
        name: "Jackson Lee",
        role: "Backend Developer",
        email: "jackson@example.com",
      },
      {
        id: "usr_003",
        name: "Sophia Kim",
        role: "UI Designer",
        email: "sophia@example.com",
      },
    ],
    []
  );

  const columns = useMemo(
    () => [
      {
        id: "select",
        header: ({ table }) => (
          <input
            type="checkbox"
            aria-label="Select all"
            checked={table.getIsAllPageRowsSelected()}
            onChange={(e) =>
              table.toggleAllPageRowsSelected(
                e.target.checked
              )
            }
          />
        ),
        cell: ({ row }) => (
          <input
            type="checkbox"
            aria-label="Select row"
            checked={row.getIsSelected()}
            onChange={(e) =>
              row.toggleSelected(
                e.target.checked
              )
            }
          />
        ),
      },
      {
        accessorKey: "name",
        header: "Name",
      },
      {
        accessorKey: "role",
        header: "Role",
      },
      {
        accessorKey: "email",
        header: "Email",
      },
    ],
    []
  );

  return (
    <div className="w-full max-w-5xl">
      <DataTable
        columns={columns}
        data={data}
        filterColumn="email"
        filterPlaceholder="Filter emails..."
      />
    </div>
  );
}

"use client";
import { DataTable } from "@shery-ui/components";
import { useMemo } from "react";

export default function DataTablePagination() {
  const data = useMemo(
    () =>
      Array.from({ length: 20 }, (_, index) => ({
        id: `invoice_${index + 1}`,
        customer: `Customer ${index + 1}`,
        status:
          index % 3 === 0
            ? "Paid"
            : index % 3 === 1
            ? "Pending"
            : "Failed",
        amount: `$${(index + 1) * 25}`,
      })),
    []
  );

  const columns = useMemo(
    () => [
      {
        accessorKey: "customer",
        header: "Customer",
      },
      {
        accessorKey: "status",
        header: "Status",
      },
      {
        accessorKey: "amount",
        header: "Amount",
      },
    ],
    []
  );

  return (
    <div className="w-full max-w-5xl">
      <DataTable
        columns={columns}
        data={data}
        showFilter={false}
      />
    </div>
  );
}
